@Composable
private fun LoggedOutScreen(
    isWorking: Boolean,
    webClientIdConfigured: Boolean,
    supabaseConfigured: Boolean,
    status: StatusBanner?,
    showDiagnostics: Boolean,
    diagnostics: AppDiagnostics,
    onPrimarySignIn: () -> Unit,
    onSecondarySignIn: () -> Unit,
    onToggleDiagnostics: () -> Unit,
) {
    val configurationMessage = buildList {
        if (!webClientIdConfigured) add("Google Web client ID")
        if (!supabaseConfigured) add("Supabase URL / publishable key")
    }.joinToString(separator = " and ")
    val signInEnabled = webClientIdConfigured && supabaseConfigured && !isWorking

    Column(
        modifier = Modifier
            .fillMaxSize()
            .verticalScroll(rememberScrollState())
            .padding(horizontal = 24.dp, vertical = 28.dp),
        verticalArrangement = Arrangement.Center,
        horizontalAlignment = Alignment.CenterHorizontally,
    ) {
        Card(
            colors = CardDefaults.cardColors(containerColor = Color(0xFF17314F)),
            shape = RoundedCornerShape(22.dp),
        ) {
            Box(
                modifier = Modifier.size(72.dp),
                contentAlignment = Alignment.Center,
            ) {
                Icon(
                    imageVector = Icons.Outlined.AccountCircle,
                    contentDescription = null,
                    tint = Color.White,
                    modifier = Modifier.size(36.dp),
                )
            }
        }

        Spacer(modifier = Modifier.height(20.dp))

        Text(
            text = "Interior Design",
            style = MaterialTheme.typography.headlineSmall,
            fontWeight = FontWeight.Bold,
            color = Color(0xFF17212B),
        )

        Spacer(modifier = Modifier.height(8.dp))

        Text(
            text = "Sign in to continue",
            style = MaterialTheme.typography.bodyLarge,
            color = Color(0xFF52616B),
        )

        Spacer(modifier = Modifier.height(24.dp))

        Card(
            colors = CardDefaults.cardColors(containerColor = Color(0xFFFDFDFC)),
            shape = RoundedCornerShape(28.dp),
        ) {
            Column(
                modifier = Modifier.padding(24.dp),
                verticalArrangement = Arrangement.spacedBy(16.dp),
            ) {
                Text(
                    text = "Welcome back",
                    style = MaterialTheme.typography.titleLarge,
                    fontWeight = FontWeight.Bold,
                    color = Color(0xFF17212B),
                )
                Text(
                    text = "Use your Google account to sign in. Your Android session uses the same Supabase user and credits as the web app.",
                    style = MaterialTheme.typography.bodyMedium,
                    color = Color(0xFF52616B),
                )

                if (configurationMessage.isNotBlank()) {
                    NoticeCard(
                        title = "Configuration required",
                        message = "Missing $configurationMessage.",
                        isError = true,
                    )
                }

                status?.let { banner ->
                    NoticeCard(
                        title = banner.title,
                        message = banner.message,
                        isError = banner.isError,
                    )
                }

                OutlinedButton(
                    onClick = onPrimarySignIn,
                    enabled = signInEnabled,
                    modifier = Modifier.fillMaxWidth(),
                    shape = RoundedCornerShape(18.dp),
                    colors = ButtonDefaults.outlinedButtonColors(
                        containerColor = Color.White,
                        contentColor = Color(0xFF111827),
                    ),
                ) {
                    if (isWorking) {
                        CircularProgressIndicator(
                            modifier = Modifier.size(18.dp),
                            strokeWidth = 2.dp,
                            color = Color(0xFF0F7B6C),
                        )
                        Spacer(modifier = Modifier.size(12.dp))
                        Text("Signing in...")
                    } else {
                        GoogleMark()
                        Spacer(modifier = Modifier.size(12.dp))
                        Text(
                            text = "Sign in with Google",
                            style = MaterialTheme.typography.titleMedium,
                            fontWeight = FontWeight.Medium,
                        )
                    }
                }

                Text(
                    text = "By continuing, you use the Google account linked to your design workspace.",
                    style = MaterialTheme.typography.bodySmall,
                    color = Color(0xFF667085),
                )

                TextButton(
                    onClick = onSecondarySignIn,
                    enabled = signInEnabled,
                    modifier = Modifier.align(Alignment.CenterHorizontally),
                ) {
                    Text("Try alternate Google flow")
                }

                TextButton(
                    onClick = onToggleDiagnostics,
                    modifier = Modifier.align(Alignment.CenterHorizontally),
                ) {
                    Text(if (showDiagnostics) "Hide setup details" else "Show setup details")
                }
            }
        }

        if (showDiagnostics) {
            Spacer(modifier = Modifier.height(16.dp))
            DiagnosticsCard(diagnostics = diagnostics)
        }

        Spacer(modifier = Modifier.height(16.dp))
        Text(
            text = "Sign-in is handled by Credential Manager and converted into a Supabase session.",
            style = MaterialTheme.typography.bodySmall,
            color = Color(0xFF667085),
            textAlign = TextAlign.Center,
            modifier = Modifier.fillMaxWidth(),
        )
    }
}

