private class AppAuthClient(context: Context) {
    private val credentialManager = CredentialManager.create(context)
    private val supabase = createSupabaseClient(
        supabaseUrl = BuildConfig.SUPABASE_URL,
        supabaseKey = BuildConfig.SUPABASE_PUBLISHABLE_KEY,
    ) {
        defaultSerializer = KotlinXSerializer(
            Json {
                ignoreUnknownKeys = true
                explicitNulls = false
            },
        )
        install(Auth)
        install(Postgrest) {
            defaultSchema = "public"
        }
    }

    suspend fun restoreSession(): AuthenticatedAccount? {
        val user = supabase.auth.currentUserOrNull() ?: return null
        val accessToken = supabase.auth.currentAccessTokenOrNull() ?: return null
        return buildAccount(
            userId = user.id,
            fallbackEmail = user.email,
            metadata = user.userMetadata,
            accessToken = accessToken,
            googleIdToken = null,
        )
    }

    suspend fun refreshAccount(): AuthenticatedAccount {
        val user = supabase.auth.currentUserOrNull()
            ?: error("No Supabase session is available to refresh.")
        val accessToken = supabase.auth.currentAccessTokenOrNull()
            ?: error("No Supabase access token is available.")
        return buildAccount(
            userId = user.id,
            fallbackEmail = user.email,
            metadata = user.userMetadata,
            accessToken = accessToken,
            googleIdToken = null,
        )
    }

    suspend fun signInWithBottomSheet(activity: Activity): AuthenticatedAccount {
        val primaryRequest = buildAuthorizedAccountsRequest()

        return try {
            signInWithRequest(activity, primaryRequest)
        } catch (exception: NoCredentialException) {
            signInWithRequest(activity, buildAllAccountsRequest())
        }
    }

    suspend fun signInWithGoogleButton(activity: Activity): AuthenticatedAccount {
        return signInWithRequest(activity, buildExplicitGoogleButtonRequest())
    }

    suspend fun signOut() {
        runCatching { supabase.auth.signOut() }.getOrThrow()
        try {
            credentialManager.clearCredentialState(ClearCredentialStateRequest())
        } catch (exception: ClearCredentialException) {
            throw exception
        }
    }

    private suspend fun signInWithRequest(
        activity: Activity,
        requestSpec: CredentialRequestSpec,
    ): AuthenticatedAccount {
        val response = credentialManager.getCredential(
            context = activity,
            request = requestSpec.request,
        )
        val googleCredential = response.toGoogleCredential(requestSpec.rawNonce)

        supabase.auth.signInWith(IDToken) {
            provider = Google
            idToken = googleCredential.idToken
            nonce = googleCredential.rawNonce
        }

        val currentUser = supabase.auth.currentUserOrNull()
            ?: error("Supabase session was not created after Google sign-in.")
        val accessToken = supabase.auth.currentAccessTokenOrNull()
            ?: error("Supabase access token was not available after sign-in.")

        return buildAccount(
            userId = currentUser.id,
            fallbackEmail = currentUser.email ?: googleCredential.email,
            metadata = currentUser.userMetadata,
            accessToken = accessToken,
            googleIdToken = googleCredential.idToken,
        )
    }

    private suspend fun buildAccount(
        userId: String,
        fallbackEmail: String?,
        metadata: JsonObject?,
        accessToken: String,
        googleIdToken: String?,
    ): AuthenticatedAccount {
        val profile = fetchProfileWithRetry(userId)
        val displayName = profile?.fullName
            ?: metadata.stringValue("full_name")
            ?: metadata.stringValue("name")
            ?: fallbackEmail
            ?: userId

        return AuthenticatedAccount(
            userId = userId,
            email = profile?.email ?: fallbackEmail ?: userId,
            displayName = displayName,
            avatarUrl = profile?.avatarUrl
                ?: metadata.stringValue("avatar_url")
                ?: metadata.stringValue("picture"),
            credits = profile?.credits ?: 0L,
            isPayingCustomer = profile?.isPayingCustomer ?: false,
            accessToken = accessToken,
            googleIdToken = googleIdToken,
            isProvisioningProfile = profile == null,
        )
    }

    private suspend fun fetchProfileWithRetry(userId: String): AppUserProfile? {
        repeat(5) { attempt ->
            val result = runCatching {
                supabase.from("users").select(
                    columns = Columns.list("id,email,full_name,avatar_url,credits,is_paying_customer"),
                ) {
                    filter {
                        eq("id", userId)
                    }
                    limit(1)
                    single()
                }.decodeAs<AppUserProfile>()
            }

            result.onSuccess { return it }

            val error = result.exceptionOrNull() ?: return null
            val shouldRetry = error.looksLikeMissingProfile() && attempt < 4
            if (!shouldRetry) {
                throw error
            }
            delay(400L * (attempt + 1))
        }

        return null
    }

    private fun buildAuthorizedAccountsRequest(): CredentialRequestSpec {
        val rawNonce = generateSecureRandomNonce()
        val option = GetGoogleIdOption.Builder()
            .setFilterByAuthorizedAccounts(true)
            .setServerClientId(BuildConfig.WEB_CLIENT_ID)
            .setAutoSelectEnabled(true)
            .setNonce(rawNonce.sha256Hex())
            .build()

        return CredentialRequestSpec(
            request = buildRequest(option),
            rawNonce = rawNonce,
        )
    }

    private fun buildAllAccountsRequest(): CredentialRequestSpec {
        val rawNonce = generateSecureRandomNonce()
        val option = GetGoogleIdOption.Builder()
            .setFilterByAuthorizedAccounts(false)
            .setServerClientId(BuildConfig.WEB_CLIENT_ID)
            .setNonce(rawNonce.sha256Hex())
            .build()

        return CredentialRequestSpec(
            request = buildRequest(option),
            rawNonce = rawNonce,
        )
    }

    private fun buildExplicitGoogleButtonRequest(): CredentialRequestSpec {
        val rawNonce = generateSecureRandomNonce()
        val option = GetSignInWithGoogleOption.Builder(BuildConfig.WEB_CLIENT_ID)
            .setNonce(rawNonce.sha256Hex())
            .build()

        return CredentialRequestSpec(
            request = buildRequest(option),
            rawNonce = rawNonce,
        )
    }

    private fun buildRequest(option: androidx.credentials.CredentialOption): GetCredentialRequest {
        return GetCredentialRequest.Builder()
            .addCredentialOption(option)
            .build()
    }
}

private fun GetCredentialResponse.toGoogleCredential(rawNonce: String): GoogleCredentialResult {
    val returnedCredential = credential

    if (returnedCredential !is CustomCredential) {
        error("Unexpected credential type: ${returnedCredential::class.java.simpleName}")
    }

    if (returnedCredential.type != GoogleIdTokenCredential.TYPE_GOOGLE_ID_TOKEN_CREDENTIAL) {
        error("Unexpected custom credential type: ${returnedCredential.type}")
    }

    return try {
        val googleCredential = GoogleIdTokenCredential.createFrom(returnedCredential.data)
        GoogleCredentialResult(
            email = googleCredential.id,
            displayName = googleCredential.displayName,
            givenName = googleCredential.givenName,
            familyName = googleCredential.familyName,
            profilePictureUri = googleCredential.profilePictureUri?.toString(),
            idToken = googleCredential.idToken,
            rawNonce = rawNonce,
        )
    } catch (exception: GoogleIdTokenParsingException) {
        throw IllegalStateException(
            "Google ID token parsing failed. Update the googleid dependency if needed.",
            exception,
        )
    }
}

private data class AuthUiState(
    val isInitializing: Boolean = true,
    val isWorking: Boolean = false,
    val account: AuthenticatedAccount? = null,
    val status: StatusBanner? = null,
)

private data class StatusBanner(
    val title: String,
    val message: String,
    val isError: Boolean,
)

private data class CredentialRequestSpec(
    val request: GetCredentialRequest,
    val rawNonce: String,
)

private data class GoogleCredentialResult(
    val email: String,
    val displayName: String?,
    val givenName: String?,
    val familyName: String?,
    val profilePictureUri: String?,
    val idToken: String,
    val rawNonce: String,
) {
    val displayLabel: String
        get() = displayName ?: givenName ?: email
}

private data class AuthenticatedAccount(
    val userId: String,
    val email: String,
    val displayName: String,
    val avatarUrl: String?,
    val credits: Long,
    val isPayingCustomer: Boolean,
    val accessToken: String,
    val googleIdToken: String?,
    val isProvisioningProfile: Boolean,
) {
    val displayLabel: String
        get() = displayName.ifBlank { email }
}

@Serializable
private data class AppUserProfile(
    val id: String,
    val email: String,
    @SerialName("full_name")
    val fullName: String? = null,
    @SerialName("avatar_url")
    val avatarUrl: String? = null,
    val credits: Long = 0L,
    @SerialName("is_paying_customer")
    val isPayingCustomer: Boolean = false,
)

private data class AppDiagnostics(
    val packageName: String,
    val webClientId: String,
    val supabaseUrl: String,
    val signingSha1: String,
    val signingSha256: String,
)

private fun generateSecureRandomNonce(byteLength: Int = 32): String {
    val randomBytes = ByteArray(byteLength)
    SecureRandom().nextBytes(randomBytes)
    return Base64.encodeToString(
        randomBytes,
        Base64.NO_WRAP or Base64.URL_SAFE or Base64.NO_PADDING,
    )
}

private fun String.sha256Hex(): String {
    return MessageDigest.getInstance("SHA-256")
        .digest(toByteArray())
        .joinToString("") { byte -> "%02x".format(byte) }
}

private fun Throwable.toUserMessage(): String {
    val rawMessage = message ?: javaClass.simpleName

    return when (this) {
        is NoCredentialException -> {
            "No matching Google credential was returned. Common causes: no Google account on the device, the Android OAuth client is missing this app's package/SHA, or the Google account has not approved this client yet."
        }
        is GetCredentialCancellationException -> "The sign-in sheet was dismissed before a credential was selected."
        is GetCredentialProviderConfigurationException -> "Credential providers are not configured correctly on this device."
        is GetCredentialUnknownException -> "Credential Manager returned an unknown error."
        is GetCredentialException -> rawMessage
        is ClearCredentialException -> rawMessage
        else -> {
            when {
                rawMessage.contains("Invalid login credentials", ignoreCase = true) -> {
                    "Supabase rejected the Google ID token. Verify the Google provider setup in Supabase and make sure the Web client ID belongs to the same project."
                }
                rawMessage.contains("JWT", ignoreCase = true) -> {
                    "Supabase session handling failed. The app could not obtain a valid access token."
                }
                rawMessage.contains("users", ignoreCase = true) && rawMessage.contains("permission", ignoreCase = true) -> {
                    "Supabase authenticated the user, but reading the `public.users` row was blocked. Check the table's RLS policies."
                }
                else -> rawMessage
            }
        }
    }
}

private fun Throwable.looksLikeMissingProfile(): Boolean {
    val value = message.orEmpty()
    return value.contains("PGRST116", ignoreCase = true) ||
        value.contains("JSON object requested", ignoreCase = true) ||
        value.contains("0 rows", ignoreCase = true)
}

private fun JsonObject?.stringValue(key: String): String? {
    return this?.get(key)?.jsonPrimitive?.contentOrNull
}

private fun String.preview(maxLength: Int = 96): String {
    return if (length <= maxLength) {
        this
    } else {
        take(maxLength) + "…"
    }
}

private tailrec fun Context.findActivity(): Activity? {
    return when (this) {
        is Activity -> this
        is ContextWrapper -> baseContext.findActivity()
        else -> null
    }
}

private fun Context.buildDiagnostics(): AppDiagnostics {
    return AppDiagnostics(
        packageName = packageName,
        webClientId = BuildConfig.WEB_CLIENT_ID,
        supabaseUrl = BuildConfig.SUPABASE_URL,
        signingSha1 = loadSigningFingerprint("SHA-1"),
        signingSha256 = loadSigningFingerprint("SHA-256"),
    )
}

private fun Context.loadSigningFingerprint(algorithm: String): String {
    return runCatching {
        val packageInfo = packageManager.getPackageInfo(
            packageName,
            PackageManager.GET_SIGNING_CERTIFICATES,
        )
        val signatureBytes = packageInfo.signingInfo
            ?.apkContentsSigners
            ?.firstOrNull()
            ?.toByteArray()
            ?: return "Unavailable"

        MessageDigest.getInstance(algorithm)
            .digest(signatureBytes)
            .joinToString(":") { byte -> "%02X".format(byte) }
    }.getOrElse {
        "Unavailable"
    }
}

