private fun generateSecureRandomNonce(byteLength: Int = 32): String {
    val randomBytes = ByteArray(byteLength)
    SecureRandom().nextBytes(randomBytes)
    return Base64.encodeToString(
        randomBytes,
        Base64.NO_WRAP or Base64.URL_SAFE or Base64.NO_PADDING,
    )
}

private fun String.sha256Hex(): String {
    return MessageDigest.getInstance("SHA-256")
        .digest(toByteArray())
        .joinToString("") { byte -> "%02x".format(byte) }
}

private fun Throwable.toUserMessage(): String {
    val rawMessage = message ?: javaClass.simpleName

    return when (this) {
        is NoCredentialException -> {
            "Kein passendes Google-Konto gefunden. Mögliche Ursachen: Kein Google-Konto auf dem Gerät, oder die OAuth-Konfiguration stimmt nicht."
        }
        is GetCredentialCancellationException -> "Die Anmeldung wurde abgebrochen."
        is GetCredentialProviderConfigurationException -> "Credential-Provider auf diesem Gerät nicht korrekt konfiguriert."
        is GetCredentialUnknownException -> "Unbekannter Fehler beim Credential Manager."
        is GetCredentialException -> rawMessage
        is ClearCredentialException -> rawMessage
        else -> rawMessage
    }
}

private tailrec fun Context.findActivity(): Activity? {
    return when (this) {
        is Activity -> this
        is ContextWrapper -> baseContext.findActivity()
        else -> null
    }
}

private fun Context.buildDiagnostics(): AppDiagnostics {
    return AppDiagnostics(
        packageName = packageName,
        webClientId = BuildConfig.WEB_CLIENT_ID,
        signingSha1 = loadSigningFingerprint("SHA-1"),
        signingSha256 = loadSigningFingerprint("SHA-256"),
    )
}

private fun Context.loadSigningFingerprint(algorithm: String): String {
    return runCatching {
        val packageInfo = packageManager.getPackageInfo(
            packageName,
            PackageManager.GET_SIGNING_CERTIFICATES,
        )
        val signatureBytes = packageInfo.signingInfo
            ?.apkContentsSigners
            ?.firstOrNull()
            ?.toByteArray()
            ?: return "Unavailable"

        MessageDigest.getInstance(algorithm)
            .digest(signatureBytes)
            .joinToString(":") { byte -> "%02X".format(byte) }
    }.getOrElse {
        "Unavailable"
    }
}

