private class AppAuthClient(context: Context) {
    private val credentialManager = CredentialManager.create(context)

    // TODO: Initialize Firebase Auth once configured
    // private val firebaseAuth = FirebaseAuth.getInstance()

    suspend fun signInWithBottomSheet(activity: Activity): AuthenticatedAccount {
        val primaryRequest = buildAuthorizedAccountsRequest()

        return try {
            signInWithRequest(activity, primaryRequest)
        } catch (exception: NoCredentialException) {
            signInWithRequest(activity, buildAllAccountsRequest())
        }
    }

    suspend fun signInWithGoogleButton(activity: Activity): AuthenticatedAccount {
        return signInWithRequest(activity, buildExplicitGoogleButtonRequest())
    }

    suspend fun signOut() {
        // TODO: Sign out from Firebase
        // firebaseAuth.signOut()
        try {
            credentialManager.clearCredentialState(ClearCredentialStateRequest())
        } catch (exception: ClearCredentialException) {
            throw exception
        }
    }

    private suspend fun signInWithRequest(
        activity: Activity,
        requestSpec: CredentialRequestSpec,
    ): AuthenticatedAccount {
        val response = credentialManager.getCredential(
            context = activity,
            request = requestSpec.request,
        )
        val googleCredential = response.toGoogleCredential(requestSpec.rawNonce)

        // TODO: Exchange Google ID token for Firebase credential
        // val firebaseCredential = GoogleAuthProvider.getCredential(googleCredential.idToken, null)
        // firebaseAuth.signInWithCredential(firebaseCredential).await()
        // val firebaseUser = firebaseAuth.currentUser ?: error("Firebase sign-in failed")

        return AuthenticatedAccount(
            userId = googleCredential.email,
            email = googleCredential.email,
            displayName = googleCredential.displayName ?: googleCredential.email,
            avatarUrl = googleCredential.profilePictureUri,
            googleIdToken = googleCredential.idToken,
        )
    }

    private fun buildAuthorizedAccountsRequest(): CredentialRequestSpec {
        val rawNonce = generateSecureRandomNonce()
        val option = GetGoogleIdOption.Builder()
            .setFilterByAuthorizedAccounts(true)
            .setServerClientId(BuildConfig.WEB_CLIENT_ID)
            .setAutoSelectEnabled(true)
            .setNonce(rawNonce.sha256Hex())
            .build()

        return CredentialRequestSpec(
            request = buildRequest(option),
            rawNonce = rawNonce,
        )
    }

    private fun buildAllAccountsRequest(): CredentialRequestSpec {
        val rawNonce = generateSecureRandomNonce()
        val option = GetGoogleIdOption.Builder()
            .setFilterByAuthorizedAccounts(false)
            .setServerClientId(BuildConfig.WEB_CLIENT_ID)
            .setNonce(rawNonce.sha256Hex())
            .build()

        return CredentialRequestSpec(
            request = buildRequest(option),
            rawNonce = rawNonce,
        )
    }

    private fun buildExplicitGoogleButtonRequest(): CredentialRequestSpec {
        val rawNonce = generateSecureRandomNonce()
        val option = GetSignInWithGoogleOption.Builder(BuildConfig.WEB_CLIENT_ID)
            .setNonce(rawNonce.sha256Hex())
            .build()

        return CredentialRequestSpec(
            request = buildRequest(option),
            rawNonce = rawNonce,
        )
    }

    private fun buildRequest(option: androidx.credentials.CredentialOption): GetCredentialRequest {
        return GetCredentialRequest.Builder()
            .addCredentialOption(option)
            .build()
    }
}

private fun GetCredentialResponse.toGoogleCredential(rawNonce: String): GoogleCredentialResult {
    val returnedCredential = credential

    if (returnedCredential !is CustomCredential) {
        error("Unexpected credential type: ${returnedCredential::class.java.simpleName}")
    }

    if (returnedCredential.type != GoogleIdTokenCredential.TYPE_GOOGLE_ID_TOKEN_CREDENTIAL) {
        error("Unexpected custom credential type: ${returnedCredential.type}")
    }

    return try {
        val googleCredential = GoogleIdTokenCredential.createFrom(returnedCredential.data)
        GoogleCredentialResult(
            email = googleCredential.id,
            displayName = googleCredential.displayName,
            givenName = googleCredential.givenName,
            familyName = googleCredential.familyName,
            profilePictureUri = googleCredential.profilePictureUri?.toString(),
            idToken = googleCredential.idToken,
            rawNonce = rawNonce,
        )
    } catch (exception: GoogleIdTokenParsingException) {
        throw IllegalStateException(
            "Google ID token parsing failed. Update the googleid dependency if needed.",
            exception,
        )
    }
}

private data class AuthUiState(
    val isInitializing: Boolean = true,
    val isWorking: Boolean = false,
    val account: AuthenticatedAccount? = null,
    val status: StatusBanner? = null,
)

private data class StatusBanner(
    val title: String,
    val message: String,
    val isError: Boolean,
)

private data class CredentialRequestSpec(
    val request: GetCredentialRequest,
    val rawNonce: String,
)

private data class GoogleCredentialResult(
    val email: String,
    val displayName: String?,
    val givenName: String?,
    val familyName: String?,
    val profilePictureUri: String?,
    val idToken: String,
    val rawNonce: String,
)

private data class AuthenticatedAccount(
    val userId: String,
    val email: String,
    val displayName: String,
    val avatarUrl: String?,
    val googleIdToken: String?,
) {
    val displayLabel: String
        get() = displayName.ifBlank { email }
}

private data class AppDiagnostics(
    val packageName: String,
    val webClientId: String,
    val signingSha1: String,
    val signingSha256: String,
)

private fun generateSecureRandomNonce(byteLength: Int = 32): String {
    val randomBytes = ByteArray(byteLength)
    SecureRandom().nextBytes(randomBytes)
    return Base64.encodeToString(
        randomBytes,
        Base64.NO_WRAP or Base64.URL_SAFE or Base64.NO_PADDING,
    )
}

private fun String.sha256Hex(): String {
    return MessageDigest.getInstance("SHA-256")
        .digest(toByteArray())
        .joinToString("") { byte -> "%02x".format(byte) }
}

private fun Throwable.toUserMessage(): String {
    val rawMessage = message ?: javaClass.simpleName

    return when (this) {
        is NoCredentialException -> {
            "Kein passendes Google-Konto gefunden. Mögliche Ursachen: Kein Google-Konto auf dem Gerät, oder die OAuth-Konfiguration stimmt nicht."
        }
        is GetCredentialCancellationException -> "Die Anmeldung wurde abgebrochen."
        is GetCredentialProviderConfigurationException -> "Credential-Provider auf diesem Gerät nicht korrekt konfiguriert."
        is GetCredentialUnknownException -> "Unbekannter Fehler beim Credential Manager."
        is GetCredentialException -> rawMessage
        is ClearCredentialException -> rawMessage
        else -> rawMessage
    }
}

private tailrec fun Context.findActivity(): Activity? {
    return when (this) {
        is Activity -> this
        is ContextWrapper -> baseContext.findActivity()
        else -> null
    }
}

private fun Context.buildDiagnostics(): AppDiagnostics {
    return AppDiagnostics(
        packageName = packageName,
        webClientId = BuildConfig.WEB_CLIENT_ID,
        signingSha1 = loadSigningFingerprint("SHA-1"),
        signingSha256 = loadSigningFingerprint("SHA-256"),
    )
}

private fun Context.loadSigningFingerprint(algorithm: String): String {
    return runCatching {
        val packageInfo = packageManager.getPackageInfo(
            packageName,
            PackageManager.GET_SIGNING_CERTIFICATES,
        )
        val signatureBytes = packageInfo.signingInfo
            ?.apkContentsSigners
            ?.firstOrNull()
            ?.toByteArray()
            ?: return "Unavailable"

        MessageDigest.getInstance(algorithm)
            .digest(signatureBytes)
            .joinToString(":") { byte -> "%02X".format(byte) }
    }.getOrElse {
        "Unavailable"
    }
}

