@Composable
private fun SignInScreen(authClient: AppAuthClient) {
    val context = LocalContext.current
    val activity = remember(context) { context.findActivity() }
    val diagnostics = remember(context) { context.buildDiagnostics() }
    val scope = rememberCoroutineScope()
    val webClientIdConfigured = remember {
        BuildConfig.WEB_CLIENT_ID.isNotBlank() && BuildConfig.WEB_CLIENT_ID != PlaceholderWebClientId
    }
    var showDiagnostics by remember { mutableStateOf(false) }
    var uiState by remember { mutableStateOf(AuthUiState()) }

    LaunchedEffect(authClient) {
        uiState = try {
            uiState.copy(
                isInitializing = false,
                account = authClient.restoreSession(),
            )
        } catch (exception: Throwable) {
            Log.e(Tag, "Session restore failed", exception)
            uiState.copy(
                isInitializing = false,
                status = StatusBanner(
                    title = "Session restore failed",
                    message = exception.toUserMessage(),
                    isError = true,
                ),
            )
        }
    }

    fun launchSignIn(block: suspend (Activity) -> AuthenticatedAccount) {
        val currentActivity = activity ?: run {
            uiState = uiState.copy(
                status = StatusBanner(
                    title = "No activity context",
                    message = "Credential Manager needs an Activity context to open Google Sign-In.",
                    isError = true,
                ),
            )
            return
        }

        scope.launch {
            uiState = uiState.copy(isWorking = true, status = null)
            uiState = try {
                val account = block(currentActivity)
                uiState.copy(
                    isWorking = false,
                    account = account,
                    status = StatusBanner(
                        title = "Signed in",
                        message = "Signed in as ${account.displayLabel}.",
                        isError = false,
                    ),
                )
            } catch (exception: Throwable) {
                Log.e(Tag, "Sign-in action failed", exception)
                uiState.copy(
                    isWorking = false,
                    status = StatusBanner(
                        title = "Sign-in failed",
                        message = exception.toUserMessage(),
                        isError = true,
                    ),
                )
            }
        }
    }

    Box(
        modifier = Modifier
            .fillMaxSize()
            .background(
                brush = Brush.verticalGradient(
                    colors = listOf(
                        Color(0xFFE0F7FA),
                        Color(0xFFB2EBF2),
                        Color(0xFF80DEEA),
                    ),
                ),
            ),
    ) {
        DecorativeBackdrop()

        when {
            uiState.isInitializing -> {
                LoadingScreen()
            }
            uiState.account == null -> {
                LoggedOutScreen(
                    isWorking = uiState.isWorking,
                    webClientIdConfigured = webClientIdConfigured,
                    status = uiState.status,
                    showDiagnostics = showDiagnostics,
                    diagnostics = diagnostics,
                    onPrimarySignIn = {
                        launchSignIn { currentActivity ->
                            authClient.signInWithBottomSheet(currentActivity)
                        }
                    },
                    onSecondarySignIn = {
                        launchSignIn { currentActivity ->
                            authClient.signInWithGoogleButton(currentActivity)
                        }
                    },
                    onToggleDiagnostics = { showDiagnostics = !showDiagnostics },
                )
            }
            else -> {
                LoggedInScreen(
                    account = uiState.account,
                    isWorking = uiState.isWorking,
                    onSignOut = {
                        scope.launch {
                            uiState = uiState.copy(isWorking = true, status = null)
                            uiState = try {
                                authClient.signOut()
                                uiState.copy(
                                    isWorking = false,
                                    account = null,
                                    status = StatusBanner(
                                        title = "Signed out",
                                        message = "Session and Credential Manager state were cleared.",
                                        isError = false,
                                    ),
                                )
                            } catch (exception: Throwable) {
                                Log.e(Tag, "Sign-out failed", exception)
                                uiState.copy(
                                    isWorking = false,
                                    status = StatusBanner(
                                        title = "Sign-out failed",
                                        message = exception.toUserMessage(),
                                        isError = true,
                                    ),
                                )
                            }
                        }
                    },
                )
            }
        }
    }
}

