@Composable
private fun LoggedOutScreen(
    isWorking: Boolean,
    webClientIdConfigured: Boolean,
    status: StatusBanner?,
    showDiagnostics: Boolean,
    diagnostics: AppDiagnostics,
    onPrimarySignIn: () -> Unit,
    onSecondarySignIn: () -> Unit,
    onToggleDiagnostics: () -> Unit,
) {
    val signInEnabled = webClientIdConfigured && !isWorking

    Column(
        modifier = Modifier
            .fillMaxSize()
            .verticalScroll(rememberScrollState())
            .padding(horizontal = 24.dp, vertical = 28.dp),
        verticalArrangement = Arrangement.Center,
        horizontalAlignment = Alignment.CenterHorizontally,
    ) {
        Card(
            colors = CardDefaults.cardColors(containerColor = WaterDark),
            shape = RoundedCornerShape(22.dp),
        ) {
            Box(
                modifier = Modifier.size(72.dp),
                contentAlignment = Alignment.Center,
            ) {
                Text(
                    text = "\uD83D\uDEB0",
                    style = MaterialTheme.typography.headlineLarge,
                )
            }
        }

        Spacer(modifier = Modifier.height(20.dp))

        Text(
            text = "Trinkbrunnen Zürich",
            style = MaterialTheme.typography.headlineSmall,
            fontWeight = FontWeight.Bold,
            color = TextPrimary,
        )

        Spacer(modifier = Modifier.height(8.dp))

        Text(
            text = "Entdecke die Trinkbrunnen deiner Stadt",
            style = MaterialTheme.typography.bodyLarge,
            color = TextSecondary,
        )

        Spacer(modifier = Modifier.height(24.dp))

        Card(
            colors = CardDefaults.cardColors(containerColor = Color(0xFFFDFDFC)),
            shape = RoundedCornerShape(28.dp),
        ) {
            Column(
                modifier = Modifier.padding(24.dp),
                verticalArrangement = Arrangement.spacedBy(16.dp),
            ) {
                Text(
                    text = "Willkommen",
                    style = MaterialTheme.typography.titleLarge,
                    fontWeight = FontWeight.Bold,
                    color = TextPrimary,
                )
                Text(
                    text = "Melde dich mit deinem Google-Konto an, um Brunnen zu entdecken, einzuchecken und Punkte zu sammeln.",
                    style = MaterialTheme.typography.bodyMedium,
                    color = TextSecondary,
                )

                if (!webClientIdConfigured) {
                    NoticeCard(
                        title = "Konfiguration erforderlich",
                        message = "Google Web Client ID fehlt. Setze WEB_CLIENT_ID in gradle.properties.",
                        isError = true,
                    )
                }

                status?.let { banner ->
                    NoticeCard(
                        title = banner.title,
                        message = banner.message,
                        isError = banner.isError,
                    )
                }

                OutlinedButton(
                    onClick = onPrimarySignIn,
                    enabled = signInEnabled,
                    modifier = Modifier.fillMaxWidth(),
                    shape = RoundedCornerShape(18.dp),
                    colors = ButtonDefaults.outlinedButtonColors(
                        containerColor = Color.White,
                        contentColor = Color(0xFF111827),
                    ),
                ) {
                    if (isWorking) {
                        CircularProgressIndicator(
                            modifier = Modifier.size(18.dp),
                            strokeWidth = 2.dp,
                            color = WaterTeal,
                        )
                        Spacer(modifier = Modifier.size(12.dp))
                        Text("Anmeldung läuft...")
                    } else {
                        GoogleMark()
                        Spacer(modifier = Modifier.size(12.dp))
                        Text(
                            text = "Mit Google anmelden",
                            style = MaterialTheme.typography.titleMedium,
                            fontWeight = FontWeight.Medium,
                        )
                    }
                }

                TextButton(
                    onClick = onSecondarySignIn,
                    enabled = signInEnabled,
                    modifier = Modifier.align(Alignment.CenterHorizontally),
                ) {
                    Text("Alternativer Google-Login")
                }

                TextButton(
                    onClick = onToggleDiagnostics,
                    modifier = Modifier.align(Alignment.CenterHorizontally),
                ) {
                    Text(if (showDiagnostics) "Setup-Details ausblenden" else "Setup-Details anzeigen")
                }
            }
        }

        if (showDiagnostics) {
            Spacer(modifier = Modifier.height(16.dp))
            DiagnosticsCard(diagnostics = diagnostics)
        }
    }
}

